head.b:skin:
/* --- POLITICS & HUMAN RIGHTS THEME VARIABLES --- */
:root {
  --primary: #c0392b;
  --primary-dark: #a93226;
  --bg-dark: #0a0a0a;
  --bg-card: #141414;
  --text-main: #ecf0f1;
  --text-muted: #95a5a6;
  --border: #2c3e50;
  --header-bg: #050505;
}

* { box-sizing: border-box; outline: none; }
body {
  margin: 0; padding: 0;
  font-family: 'Vazir', sans-serif;
  background-color: var(--bg-dark);
  color: var(--text-main);
  direction: rtl;
  font-size: 14px;
  line-height: 1.7;
}
a { text-decoration: none; color: inherit; transition: 0.3s; }
a:hover { color: var(--primary); }
img { max-width: 100%; height: auto; display: block; }
ul { list-style: none; padding: 0; margin: 0; }

.alert-bar {
  background: var(--primary);
  color: #fff;
  font-size: 12px;
  padding: 8px 0;
  display: flex;
  align-items: center;
}
.alert-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 15px;
  display: flex;
  width: 100%;
}
.alert-title {
  background: #000;
  padding: 2px 10px;
  border-radius: 4px;
  font-weight: 900;
  margin-left: 15px;
  white-space: nowrap;
  text-transform: uppercase;
}
.alert-marquee { flex: 1; font-weight: bold; }

.site-header {
  background: var(--header-bg);
  padding: 25px 0;
  border-bottom: 1px solid var(--border);
}
.header-content {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 15px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.logo-text h1 {
  font-size: 32px;
  font-weight: 900;
  letter-spacing: -1px;
  margin: 0;
}
.logo-text span { color: var(--primary); }
.header-date { color: var(--text-muted); font-size: 12px; }

.lang-switcher {
  display: flex;
  gap: 10px;
}
.lang-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  background: transparent;
  border: 2px solid transparent;
  padding: 0;
  width: 32px;
  height: 32px;
  border-radius: 50%;
  transition: 0.3s;
}
.lang-btn:hover {
  border-color: var(--primary);
  transform: scale(1.1);
}
.lang-btn img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  border-radius: 50%;
}

.lang-btn .btn-spinner{display:none;width:14px;height:14px;border:2px solid rgba(255,255,255,0.3);border-top-color:#fff;border-radius:50%;animation:langSpin .6s linear infinite;}
.lang-btn.translating .btn-spinner{display:inline-block;}
.lang-btn.translating .btn-flag{display:none;}
.lang-btn.active{border-color:var(--primary)!important; transform: scale(1.1);}
@keyframes langSpin{to{transform:rotate(360deg);}}
.translate-toast{position:fixed;bottom:30px;left:50%;transform:translateX(-50%) translateY(100px);padding:12px 24px;background:rgba(30,30,40,.95);color:#fff;border-radius:12px;font-size:14px;z-index:99999;backdrop-filter:blur(10px);border:1px solid rgba(255,255,255,.1);box-shadow:0 8px 32px rgba(0,0,0,.4);transition:transform .4s cubic-bezier(.34,1.56,.64,1);direction:ltr;}
.translate-toast.show{transform:translateX(-50%) translateY(0);}
.translate-toast.error{border-color:rgba(234,67,53,.4);}
.translate-toast.success{border-color:rgba(52,168,83,.4);}

.main-nav {
  background: #0f0f0f;
  border-bottom: 2px solid var(--border);
  position: sticky; top: 0; z-index: 999;
}
.nav-inner {
  max-width: 1200px; margin: 0 auto; padding: 0 15px;
  display: flex; height: 50px; align-items: center;
}
.nav-links { display: flex; gap: 25px; height: 100%; }
.nav-links a {
  display: flex; align-items: center; height: 100%;
  font-weight: 700; font-size: 13px; color: #ccc;
  border-top: 3px solid transparent; text-decoration: none;
}
.nav-links a:hover { color: #fff; border-top-color: var(--primary); }

.has-dropdown { position: relative; display: flex; align-items: center; height: 100%; }
.dropdown-menu {
  position: absolute; top: 100%; right: 0; background: #111;
  border: 1px solid #333; border-top: 2px solid var(--primary);
  min-width: 200px; display: none; flex-direction: column; z-index: 1000;
  box-shadow: 0 4px 10px rgba(0,0,0,0.5);
}
.has-dropdown:hover .dropdown-menu { display: flex; }
.dropdown-menu a {
  height: 40px; padding: 0 15px; border: none; border-bottom: 1px solid #222;
  color: #ccc; background: #111;
}
.dropdown-menu a:hover { background: #222; color: #fff; border-top-color: transparent !important; }
.nav-search { margin-right: auto; }
.nav-search input {
  background: #222; border: 1px solid #333; color: #fff;
  padding: 6px 15px; border-radius: 20px 0 0 20px; font-family: inherit; font-size: 12px;
  width: 150px;
}
.search-btn {
  background: var(--primary);
  border: none;
  color: #fff;
  padding: 6px 12px;
  border-radius: 0 20px 20px 0;
  cursor: pointer;
  transition: 0.3s;
}
.search-btn:hover { background: var(--primary-dark); }

.main-container {
  max-width: 1200px; margin: 40px auto; padding: 0 15px;
  display: grid; grid-template-columns: 800px 1fr; gap: 40px;
}

.hero-post {
  position: relative;
  margin-bottom: 40px;
  border-radius: 8px;
  overflow: hidden;
  box-shadow: 0 10px 30px rgba(0,0,0,0.5);
}
.hero-thumb {
  width: 100%; height: 450px; object-fit: cover;
  filter: brightness(0.7);
  transition: 0.5s;
}
.hero-post:hover .hero-thumb { filter: brightness(0.9) scale(1.05); }
.hero-content {
  position: absolute; bottom: 0; right: 0; left: 0;
  padding: 40px;
  background: linear-gradient(to top, rgba(0,0,0,0.9), transparent);
}
.hero-cat {
  background: var(--primary); color: #fff;
  padding: 4px 10px; font-size: 11px; font-weight: bold;
  border-radius: 2px; text-transform: uppercase;
  margin-bottom: 10px; display: inline-block;
}
.hero-title {
  font-size: 36px; font-weight: 900; color: #fff;
  margin: 10px 0; line-height: 1.3; text-shadow: 0 2px 4px rgba(0,0,0,0.5);
}
.hero-meta { color: #ccc; font-size: 12px; }

.homepage-loop {
  display: flex;
  flex-wrap: wrap;
  gap: 20px;
}
.hero-post, .news-grid-title {
  width: 100%;
}
.post-card {
  background: var(--bg-card);
  border: 1px solid #222;
  border-radius: 6px; overflow: hidden;
  display: flex; flex-direction: column;
  transition: 0.3s;
  width: calc(50% - 10px);
}

.post-card:hover { border-color: var(--primary); transform: translateY(-3px); }
.card-thumb { height: 180px; overflow: hidden; position: relative; }
.card-thumb img { width: 100%; height: 100%; object-fit: cover; transition: 0.5s; }
.post-card:hover .card-thumb img { transform: scale(1.1); }
.card-body { padding: 20px; }
.card-title { font-size: 16px; font-weight: 800; margin-bottom: 10px; line-height: 1.5; height: 48px; overflow: hidden; }
.card-excerpt { font-size: 13px; color: var(--text-muted); height: 60px; overflow: hidden; margin-bottom: 15px; }

.widget-box {
  background: var(--bg-card);
  border: 1px solid #222;
  border-radius: 6px;
  padding: 25px;
  margin-bottom: 30px;
}
.widget-header {
  font-size: 14px; font-weight: 900;
  color: #fff; text-transform: uppercase;
  border-bottom: 2px solid var(--primary);
  padding-bottom: 10px; margin-bottom: 20px;
  letter-spacing: 1px;
}

.stat-row { display: flex; justify-content: space-between; align-items: center; padding: 10px 0; border-bottom: 1px solid #222; }
.stat-row:last-child { border: none; }
.stat-label { font-size: 13px; color: #aaa; }
.stat-val { font-weight: bold; color: #fff; }
.stat-graph { height: 4px; background: #222; width: 100%; margin-top: 5px; border-radius: 2px; overflow: hidden; }
.stat-bar { height: 100%; background: var(--primary); }

.quote-box { text-align: center; }
.quote-img { width: 80px; height: 80px; border-radius: 50%; object-fit: cover; margin: 0 auto 15px; border: 2px solid var(--primary); }
.quote-text { font-style: italic; font-size: 14px; color: #ccc; margin-bottom: 15px; line-height: 1.6; }
.quote-author { font-weight: bold; color: #fff; font-size: 12px; }

.main-footer {
  background: #050505; border-top: 1px solid #222;
  padding: 60px 0 30px; margin-top: 60px;
}
.footer-inner { max-width: 1200px; margin: 0 auto; padding: 0 15px; display: grid; grid-template-columns: repeat(4, 1fr); gap: 40px; }
.footer-col h4 { color: #fff; border-bottom: 2px solid var(--primary); display: inline-block; padding-bottom: 5px; margin-bottom: 20px; }
.footer-col ul li { margin-bottom: 10px; border-bottom: 1px dotted #222; padding-bottom: 5px; }

.custom-footer-logo {
  text-align: center;
  padding: 30px 20px 15px 20px;
  border-top: 1px solid rgba(192, 57, 43, 0.25);
  margin-top: 20px;
}
.custom-footer-logo img {
  max-width: 130px;
  height: auto;
  opacity: 0.9;
  margin: 0 auto;
  transition: opacity 0.3s ease, transform 0.3s ease;
  filter: drop-shadow(0 0 8px rgba(192, 57, 43, 0.3));
}
.custom-footer-logo img:hover {
  opacity: 1;
  transform: scale(1.05);
  filter: drop-shadow(0 0 15px rgba(192, 57, 43, 0.5));
}
.custom-footer-logo .logo-text {
  color: var(--primary);
  font-size: 13px;
  margin-top: 10px;
  font-weight: bold;
  letter-spacing: 0.5px;
}

.header-content { position: relative; }
.lang-switcher { z-index: 2; }
.center-banner { position: absolute; left: 50%; transform: translateX(-50%); text-align: center; z-index: 1; width: max-content; }
.site-title { font-size: 30px; font-weight: 900; margin: 0; color: #fff; text-shadow: 0 0 10px rgba(192,57,43,0.8), 0 2px 4px rgba(0,0,0,0.8); letter-spacing: -0.5px; }
.site-badge { margin: 8px auto 0; font-size: 14px; color: #fff; font-weight: bold; background: rgba(192, 57, 43, 0.85); padding: 4px 18px; border-radius: 20px; box-shadow: 0 4px 6px rgba(0,0,0,0.4); display: inline-block; border: 1px solid #c0392b; }
.header-right { display: flex; align-items: center; gap: 15px; z-index: 2; }
.site-logo { height: 55px; width: auto; filter: drop-shadow(0 0 8px rgba(192,57,43,0.5)); transition: transform 0.3s; }
.site-logo:hover { transform: scale(1.05); }

@media (max-width: 1000px) {
  .main-container { display: flex; flex-direction: column; }
  .hero-title { font-size: 24px; }
  .news-grid { grid-template-columns: 1fr; }
  .footer-inner { grid-template-columns: 1fr; }
}

@media (max-width: 768px) {
  .header-content { flex-direction: column; padding: 15px 0 !important; gap: 15px; text-align: center; }
  .center-banner { position: relative; left: auto; transform: none; width: 100%; display: flex; flex-direction: column; align-items: center; margin-bottom: 5px; order: -1; }
  .site-title { font-size: 22px !important; white-space: normal; line-height: 1.3; }
  .site-badge { font-size: 12px !important; white-space: normal; }
  .lang-switcher { justify-content: center; width: 100%; order: 2; }
  .header-right { flex-direction: column; justify-content: center; width: 100%; order: 1; gap: 5px; }
  .site-logo { height: 45px; }
  #header-date { display: none; }

  .nav-inner { flex-direction: column; height: auto !important; padding: 10px; gap: 10px; }
  .nav-links { flex-wrap: wrap; justify-content: center; gap: 10px !important; height: auto !important; }
  .nav-links a { height: auto !important; padding: 5px; font-size: 12px; }
  .has-dropdown { height: auto !important; }
  .dropdown-menu { position: static; box-shadow: none; border: 1px solid #333; margin-top: 5px; min-width: 150px; }
  .dropdown-menu a { font-size: 11px; padding: 0 10px; }
  .nav-search { width: 100%; margin: 10px 0 0 0 !important; }
  .nav-search form { width: 100%; justify-content: center; }
  .nav-search input { width: 100% !important; max-width: 300px; padding: 8px 15px; }
}

body.script:
document.addEventListener('DOMContentLoaded', function() {
   function removeDuplicates() {
       var heroLink = document.querySelector('.hero-post a');
       if (!heroLink) return;
       var heroUrl = heroLink.href;
       var gridCards = document.querySelectorAll('.post-card');
       gridCards.forEach(function(card) {
           var cardLink = card.querySelector('a');
           if (cardLink && cardLink.href === heroUrl) {
               card.remove();
           }
       });
   }
   removeDuplicates();

   var feedUrl = '/feeds/posts/default?alt=json&max-results=6';
   fetch(feedUrl)
    .then(function(res) {
        if (!res.ok) throw new Error("Network response was not ok");
        return res.json();
    })
    .then(function(data) {
        var entries = data.feed.entry;
        var headlines = [];
        if (entries && entries.length > 0) {
           for(var i=0; i < entries.length; i++) {
               var entry = entries[i];
               var title = entry.title.$t;
               var link = "";
               for (var j = 0; j < entry.link.length; j++) {
                   if (entry.link[j].rel === "alternate") {
                       link = entry.link[j].href;
                       break;
                   }
               }
               if (link) {
                   headlines.push("<a href='" + link + "' style='color:#fff;transition:0.3s' onmouseover='this.style.color=\"#ffeb3b\"' onmouseout='this.style.color=\"#fff\"'>" + title + "</a>");
               } else {
                   headlines.push(title);
               }
           }
           var ticker = document.getElementById('live-ticker');
           if(ticker) ticker.innerHTML = headlines.join(' &nbsp;&nbsp;&bull;&nbsp;&nbsp; ');
        } else {
           throw new Error("No news items found");
        }
    })
    .catch(function(e) {
        var ticker = document.getElementById('live-ticker');
        if(ticker) ticker.innerHTML = "پوشش لحظه‌ای مهم‌ترین اخبار ایران و جهان";
    });
});

(function() {
  document.cookie = "googtrans=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;";
  document.cookie = "googtrans=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/; domain=.blogspot.com;";
  document.cookie = "googtrans=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/; domain=" + location.hostname + ";";
})();

function googleTranslateElementInit() {
  new google.translate.TranslateElement({
    pageLanguage: "fa",
    includedLanguages: "en,de",
    autoDisplay: false
  }, "google_translate_element");
}

//
function translateTo(lang) {
  var CURRENT = window._currentLang || "fa";
  if (lang === CURRENT) return;
  var btn = document.getElementById("lang-btn-" + lang);
  if (btn) btn.classList.add("translating");
  var toastEl = document.getElementById("translateToast");
  if (toastEl) {
    var msgs = {"en":"Translating to English...","de":"Übersetze auf Deutsch...","fa":"بازگشت به فارسی..."};
    toastEl.textContent = msgs[lang] || "Translating...";
    toastEl.className = "translate-toast show";
  }
  if (lang === "fa") {
    try {
      var bf = document.querySelector(".goog-te-banner-frame");
      if (bf) { if (bf.contentWindow) {
        var cl = bf.contentWindow.document.querySelector(".goog-close-link");
        if (cl) { cl.click(); updateBtns("fa"); return; }
      } }
    } catch(e) {}
    var sel = document.querySelector(".goog-te-combo");
    if (sel) { sel.value=""; sel.dispatchEvent(new Event("change")); }
    document.cookie="googtrans=;expires=Thu,01 Jan 1970 00:00:00 UTC;path=/;";
    setTimeout(function(){location.reload();},500);
    return;
  }
  if (CURRENT !== "fa") {
    var s = document.querySelector(".goog-te-combo");
    if (s) { s.value=""; s.dispatchEvent(new Event("change")); }
    setTimeout(function(){ doTranslate(lang); }, 1200);
  } else {
    doTranslate(lang);
  }
}
function doTranslate(lang) {
  var attempts = 0;
  var poll = setInterval(function() {
    attempts = attempts + 1;
    var sel = document.querySelector(".goog-te-combo");
    if (sel) {
      clearInterval(poll);
      sel.value = lang;
      sel.dispatchEvent(new Event("change"));
      updateBtns(lang);
    } else {
      if (attempts >= 30) {
        clearInterval(poll);
        var t = document.getElementById("translateToast");
        if(t){t.textContent="Translation timed out";t.className="translate-toast error show";}
        document.querySelectorAll(".lang-btn").forEach(function(b){b.classList.remove("translating");});
      }
    }
  }, 500);
}
function updateBtns(lang) {
  window._currentLang = lang;
  document.querySelectorAll(".lang-btn").forEach(function(b){b.classList.remove("active","translating");});
  var a = document.getElementById("lang-btn-" + lang);
  if(a) a.classList.add("active");
  var t = document.getElementById("translateToast");
  if(t){
    var n={"en":"English","de":"Deutsch","fa":"فارسی"};
    t.textContent="✓ " + n[lang];
    t.className="translate-toast success show";
    setTimeout(function(){t.classList.remove("show");},2500);
  }
}
//

b:if.script:
function decodeHtml(html) {
    var txt = document.createElement("textarea");
    txt.innerHTML = html;
    return txt.value;
}
var rpLabelRaw = "";
var rpLabel = decodeHtml(rpLabelRaw);
var rpCurrentUrl = "";

//
(function() {
  var rpContainer = document.getElementById('related-posts');
  if (!rpContainer) return;

  var tagEl = document.getElementById('rp-label-tag');
  if (tagEl) tagEl.textContent = rpLabel;

  if (!rpLabel) {
    rpContainer.style.display = 'none';
    return;
  }

  function toJalali(iso) {
    try {
      return new Date(iso).toLocaleDateString('fa-IR', {year:'numeric',month:'long',day:'numeric'});
    } catch(e) { return ''; }
  }

  fetch('/feeds/posts/default/-/' + encodeURIComponent(rpLabel) + '?alt=json&max-results=4&orderby=published')
    .then(function(res) { 
      if (!res.ok) throw new Error('Network error');
      return res.json(); 
    })
    .then(function(data) {
      var grid = document.getElementById('rp-main-grid');
      if (!grid) return;
      var entries = (data.feed && data.feed.entry) ? data.feed.entry : [];

      if (!entries || entries.length === 0) {
         grid.innerHTML = '<div class="rp-empty" style="grid-column: 1/-1; text-align: center; color: #888; padding: 20px;">مطلب مرتبط دیگری یافت نشد.</div>';
         return;
      }

      var html = '';
      var count = 0;
      entries.forEach(function(e) {
        if (count >= 3) return;
        var link = '';
        for (var i = 0; i < e.link.length; i++) {
          if (e.link[i].rel === 'alternate') { link = e.link[i].href; break; }
        }
        if (!link || link === rpCurrentUrl) return;

        var title = e.title.$t;
        var date = e.published ? toJalali(e.published.$t) : '';
        var cat = rpLabel;

        var img = 'https://i.postimg.cc/brCBfdxy/generated-image.png';
        if (e.media$thumbnail) {
            img = e.media$thumbnail.url.replace(/\/s[0-9]+-c\//, '/w480-h270-c/');
        } else if (e.content && e.content.$t) {
            var m = e.content.$t.match(/<img[^>]*src=["']([^"']+)["']/i);
            if (m && m[1]) img = m[1];
        }

        html +=
          '<article class="rp-card">' +
            '<a href="' + link + '" class="rp-thumb">' +
              '<img src="' + img + '" alt="' + title.replace(/"/g, '&quot;') + '" loading="lazy"/>' +
              '<div class="rp-thumb-overlay"></div>' +
              '<span class="rp-badge">' + cat + '</span>' +
            '</a>' +
            '<div class="rp-body">' +
              '<a href="' + link + '" class="rp-card-title">' + title + '</a>' +
              '<div class="rp-card-footer">' +
                '<span class="rp-date">' + date + '</span>' +
                '<a href="' + link + '" class="rp-more">بیشتر &#8250;</a>' +
              '</div>' +
            '</div>' +
          '</article>';
        count++;
      });

      if (count > 0) {
        grid.innerHTML = html;
      } else {
        grid.innerHTML = '<div class="rp-empty" style="grid-column: 1/-1; text-align: center; color: #888; padding: 20px;">مطلب مرتبط دیگری یافت نشد.</div>';
      }
    })
    .catch(function() {
      rpContainer.style.display = 'none';
    });
})();
//

b:includable.script:
//
            document.addEventListener('DOMContentLoaded', function() {
               fetch('/feeds/posts/default/-/آمار_زنده?alt=json&max-results=1')
                .then(r => r.json())
                .then(data => {
                   if(data.feed.entry && data.feed.entry.length > 0) {
                      var content = data.feed.entry[0].content.$t;
                      var jsonMatch = content.match(/\{[\s\S]*?\}/);
                      if(jsonMatch) {
                          var stats = JSON.parse(jsonMatch[0].replace(/&quot;/g, '"'));
                          document.getElementById('stat-executions').innerText = stats.executions || 'نامشخص';
                          document.getElementById('stat-arrests').innerText = stats.arrests || 'نامشخص';
                          if (stats.last_updated) document.getElementById('stat-last-updated').innerText = stats.last_updated;
                      }
                   } else {
                      document.getElementById('stat-executions').innerText = '۷۴';
                      document.getElementById('stat-arrests').innerText = '۱۱۲';
                   }
                }).catch(e => {
                      document.getElementById('stat-executions').innerText = '۶۸';
                      document.getElementById('stat-arrests').innerText = '۱۴۵';
                });
            });
            //

body.script:
(function() {
  var loading = false;
  var container = document.querySelector('.homepage-loop');
  var nextLink = document.getElementById('blog-pager-older-link');
  var nextPageUrl = nextLink ? nextLink.href : null;

  if(container && nextLink) {
    window.addEventListener('scroll', function() {
      if(loading || !nextPageUrl) return;
      if((window.innerHeight + window.scrollY) >= document.body.offsetHeight - 800) {
        loading = true;
        fetch(nextPageUrl).then(r => r.text()).then(html => {
           var doc = new DOMParser().parseFromString(html, 'text/html');
           var newPosts = doc.querySelectorAll('.post-card');
           newPosts.forEach(p => container.appendChild(p));
           var newNext = doc.getElementById('blog-pager-older-link');
           if(newNext) nextPageUrl = newNext.href; else nextPageUrl = null;
           loading = false;
        });
      }
    });
  }
})();

//
(function() {
    var logoUrl = 'https://i.postimg.cc/brCBfdxy/generated-image.png';
    var newBoxHTML = '<div data-fixed="true" style="background:#1a1a1a; padding:12px 25px; border-radius:8px; border-right:3px solid #c0392b; font-weight:bold; color:#ddd; display:inline-block; margin:30px 0 10px 0; font-size:13px; box-shadow:0 4px 10px rgba(0,0,0,0.4);"><span style="color:#c0392b; margin-left:8px;">\u062e\u0628\u0631\u06af\u0632\u0627\u0631\u06cc:</span> iranpolnews</div>';

    function applyFixes(root) {
        root = root || document;
        var imgs = root.querySelectorAll('.widget-box img, .post img');
        for (var i = 0; i < imgs.length; i++) {
            var img = imgs[i];
            if (img.dataset.wm || img.width < 150 || img.classList.contains('quote-img') || img.closest('.custom-footer-logo')) continue;
            if (img.closest('.widget-box') || img.closest('.post')) {
                img.dataset.wm = '1';
                var wrap = document.createElement('div');
                wrap.className = 'watermark-wrapper';
                wrap.style.cssText = 'position:relative;display:inline-block;max-width:100%;margin:auto;';
                img.parentNode.insertBefore(wrap, img);
                wrap.appendChild(img);
                var wm = document.createElement('img');
                wm.src = logoUrl;
                wm.style.cssText = 'position:absolute;bottom:15px;left:15px;width:80px;height:auto;opacity:0.50;pointer-events:none;z-index:10;filter:drop-shadow(0 0 4px rgba(0,0,0,0.5));';
                wrap.appendChild(wm);
            }
        }
        var allDivs = root.querySelectorAll('div');
        for (var k = 0; k < allDivs.length; k++) {
            var d = allDivs[k];
            if (d.dataset.fixed) continue;
            var bg = d.style.backgroundColor || d.style.background || '';
            var hasBg = (bg.indexOf('255') !== -1 || bg.indexOf('#fff') !== -1);
            if (hasBg && d.textContent.indexOf('\u0645\u0646\u0628\u0639') !== -1) {
                d.outerHTML = newBoxHTML;
            }
        }
        var els = root.querySelectorAll('span, p');
        for (var j = 0; j < els.length; j++) {
            var el = els[j];
            if (el.dataset.fixed) continue;
            var txt = el.textContent || '';
            if (txt.indexOf('\u0645\u0646\u0628\u0639 \u0627\u0635\u0644\u06cc \u0645\u0642\u0627\u0644\u0647:') !== -1 && txt.length < 300) {
                var parent = el.parentElement;
                for (var up = 0; up < 5; up++) {
                    if (!parent) break;
                    var pbg = parent.style.backgroundColor || parent.style.background || '';
                    if (pbg.indexOf('255') !== -1 || pbg.indexOf('#fff') !== -1) {
                        parent.outerHTML = newBoxHTML;
                        break;
                    }
                    parent = parent.parentElement;
                }
            }
        }
    }

    document.addEventListener('DOMContentLoaded', function() {
        applyFixes();
        var obs = new MutationObserver(function(m) {
            m.forEach(function(mut) {
                for (var n = 0; n < mut.addedNodes.length; n++) {
                    if (mut.addedNodes[n].nodeType === 1) applyFixes(mut.addedNodes[n]);
                }
            });
        });
        obs.observe(document.querySelector('.main-container') || document.body, {childList:true, subtree:true});
    });
})();
