(function(){
  var PROXY="https://script.google.com/macros/s/AKfycbyHanLMS6Bp5Dhi3X8jjOz-QfazvjxjQkCl_iim1hKTrwVDi1iUMczGw-nf1TRIAG9U/exec";
  var origContent=null;
  function getArticle(){return document.querySelector(".post-body")||document.querySelector(".entry-content");}
  function addGeminiBar(){
    var a=getArticle();if(!a)return;
    origContent=a.innerHTML;
    var bar=document.createElement("div");
    bar.id="geminiBar";
    bar.className="notranslate";
    bar.style.cssText="display:flex;align-items:center;gap:10px;margin:12px 0;padding:10px 16px;background:linear-gradient(135deg,rgba(66,133,244,0.12),rgba(52,168,83,0.08));border:1px solid rgba(66,133,244,0.25);border-radius:12px;direction:ltr;";
    bar.innerHTML='<div style="width:24px;height:24px;background:linear-gradient(135deg,#4285f4,#34a853,#fbbc04,#ea4335);border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:13px;color:#fff;flex-shrink:0">G</div>'+
      '<span style="font-size:13px;color:#aaa;flex-shrink:0">AI Translation:</span>'+
      '<button onclick="geminiTranslate(\x27en\x27)" id="gm-en" style="padding:6px 14px;border-radius:8px;border:1px solid rgba(66,133,244,0.3);background:rgba(66,133,244,0.1);color:#8ab4f8;font-size:12px;font-weight:600;cursor:pointer">\ud83c\uddec\ud83c\udde7 English</button>'+
      '<button onclick="geminiTranslate(\x27de\x27)" id="gm-de" style="padding:6px 14px;border-radius:8px;border:1px solid rgba(66,133,244,0.3);background:rgba(66,133,244,0.1);color:#8ab4f8;font-size:12px;font-weight:600;cursor:pointer">\ud83c\udde9\ud83c\uddea Deutsch</button>'+
      '<button onclick="geminiRevert()" id="gm-revert" style="display:none;padding:6px 14px;border-radius:8px;border:1px solid rgba(251,188,4,0.3);background:rgba(251,188,4,0.1);color:#fdd663;font-size:12px;font-weight:600;cursor:pointer">\ud83d\udd04 \u0628\u0627\u0632\u06af\u0634\u062a</button>';
    a.parentNode.insertBefore(bar,a);
  }
  window.geminiTranslate=function(lang){
    var a=getArticle();if(!a)return;
    if(!origContent)origContent=a.innerHTML;
    var text=a.innerText||a.textContent;
    if(!text||text.trim().length<10)return;
    var btn=document.getElementById("gm-"+lang);
    if(btn){btn.style.opacity="0.5";btn.textContent="\u23f3 Translating...";}
    var t=document.getElementById("translateToast");
    if(t){t.textContent="\ud83e\udd16 Translating with Gemini AI...";t.className="translate-toast show";}
    fetch(PROXY,{method:"POST",headers:{"Content-Type":"text/plain"},body:JSON.stringify({text:text.substring(0,8000),targetLang:lang})})
    .then(function(r){return r.json();})
    .then(function(d){
      if(d.success){
        var langN=lang==="en"?"English":"Deutsch";
        a.innerHTML='<div style="padding:12px 16px;background:linear-gradient(135deg,rgba(66,133,244,0.08),rgba(52,168,83,0.05));border-radius:10px;border:1px solid rgba(66,133,244,0.15);margin-bottom:16px;font-size:12px;color:#8ab4f8;direction:ltr">\ud83e\udd16 Translated by Gemini AI \u2022 <span style=color:#888>Original: \u0641\u0627\u0631\u0633\u06cc</span></div><div style="direction:ltr;text-align:left;line-height:1.9;font-size:16px;white-space:pre-wrap">'+d.translation.replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/\n/g,"<br>")+'</div>';
        document.getElementById("gm-revert").style.display="inline-block";
        if(t){t.textContent="\u2713 Gemini AI: "+langN;t.className="translate-toast success show";setTimeout(function(){t.classList.remove("show");},3000);}
      }else{
        if(t){t.textContent="\u26a0 "+d.error;t.className="translate-toast error show";}
      }
      if(btn){btn.style.opacity="1";btn.textContent=lang==="en"?"\ud83c\uddec\ud83c\udde7 English":"\ud83c\udde9\ud83c\uddea Deutsch";}
    }).catch(function(e){
      if(btn){btn.style.opacity="1";btn.textContent=lang==="en"?"\ud83c\uddec\ud83c\udde7 English":"\ud83c\udde9\ud83c\uddea Deutsch";}
      if(t){t.textContent="\u26a0 Network error";t.className="translate-toast error show";}
    });
  };
  window.geminiRevert=function(){
    var a=getArticle();if(a&&origContent){a.innerHTML=origContent;document.getElementById("gm-revert").style.display="none";}
    var t=document.getElementById("translateToast");if(t){t.textContent="\u2713 \u0628\u0627\u0632\u06af\u0634\u062a \u0628\u0647 \u0645\u062a\u0646 \u0627\u0635\u0644\u06cc";t.className="translate-toast success show";setTimeout(function(){t.classList.remove("show");},2000);}
  };
  if(document.readyState!=="loading")addGeminiBar();
  else document.addEventListener("DOMContentLoaded",addGeminiBar);
})();
//
